// Process ALL input items - n8n processes items individually, so we need to handle all
const inputItems = $input.all() || [$input.item];
const output = [];

// Process each item individually
for (const inputItem of inputItems) {
  let originalData = {};
  let currentMapUrl = '';

  // Get HTML from ScrapeOps detail page first
  let htmlContent = '';
  if (inputItem.json.response && typeof inputItem.json.response === 'string') {
    htmlContent = inputItem.json.response;
  } else if (typeof inputItem.json === 'string' && inputItem.json.length > 1000) {
    htmlContent = inputItem.json;
  } else if (inputItem.json.body && typeof inputItem.json.body === 'string') {
    htmlContent = inputItem.json.body;
  } else if (inputItem.json.data && typeof inputItem.json.data === 'string') {
    htmlContent = inputItem.json.data;
  }

  // Extract mapUrl from HTML
  let extractedMapUrl = '';
  if (htmlContent && typeof htmlContent === 'string' && htmlContent.length > 100) {
    const mapUrlPatterns = [
      /https?:\/\/[^"'<>\s]*maps\.google\.com[^"'<>\s]*place[^"'<>\s]*/i,
      /maps\.google\.com[^"'<>\s]*place[^"'<>\s]*/i,
      /\/maps\/place\/[^"'<>\s\?]+/i
    ];
    for (const pattern of mapUrlPatterns) {
      const match = htmlContent.match(pattern);
      if (match && match[0]) {
        extractedMapUrl = match[0];
        if (!extractedMapUrl.startsWith('http')) {
          extractedMapUrl = 'https://' + extractedMapUrl.split(/["'<>\s\?]/)[0];
        } else {
          extractedMapUrl = extractedMapUrl.split(/["'<>\s\?]/)[0];
        }
        break;
      }
    }
    if (!extractedMapUrl) {
      const placeIdPatterns = [/1s([^:!\/"'<>\s]+)/, /place\/([^\/\?"'<>\s]+)/];
      for (const pattern of placeIdPatterns) {
        const match = htmlContent.match(pattern);
        if (match && match[1]) {
          const nameMatch = htmlContent.match(/<h1[^>]*>([^<]+)<\/h1>/i) || 
                           htmlContent.match(/<div[^>]*class=["'][^"']*qBF1Pd[^"']*["'][^>]*>([^<]+)<\/div>/i);
          if (nameMatch && nameMatch[1]) {
            const bn = nameMatch[1].trim().replace(/\s+/g, '+');
            extractedMapUrl = `https://www.google.com/maps/place/${bn}/data=!4m7!3m6!1s${match[1]}`;
            break;
          }
        }
      }
    }
  }

  // Match with Parse Business Details
  try {
    const parseNode = $('Parse Business Listings');
    if (parseNode && parseNode.all) {
      const parseData = parseNode.all() || [];
      if (extractedMapUrl) {
        const getPlaceId = (url) => {
          if (!url) return '';
          const m1 = url.match(/1s([^:!\/]+)/);
          const m2 = url.match(/place\/([^\/\?]+)/);
          return m1 ? m1[1] : (m2 ? m2[1] : '');
        };
        const extractedPlaceId = getPlaceId(extractedMapUrl);
        for (let i = 0; i < parseData.length; i++) {
          const itemData = parseData[i].json || parseData[i];
          const itemMapUrl = itemData.mapUrl || '';
          if (itemMapUrl) {
            const itemPlaceId = getPlaceId(itemMapUrl);
            if (itemPlaceId && extractedPlaceId && itemPlaceId === extractedPlaceId) {
              originalData = itemData; currentMapUrl = itemMapUrl; break;
            }
            if (itemPlaceId && extractedPlaceId && 
                (itemPlaceId.includes(extractedPlaceId) || extractedPlaceId.includes(itemPlaceId))) {
              originalData = itemData; currentMapUrl = itemMapUrl; break;
            }
            if (itemMapUrl.includes(extractedPlaceId) || extractedMapUrl.includes(itemPlaceId)) {
              originalData = itemData; currentMapUrl = itemMapUrl; break;
            }
          }
        }
      }
      if (!originalData || Object.keys(originalData).length === 0) {
        const scrapeOpsNode = $('ScrapeOps: Fetch Business Details');
        if (scrapeOpsNode && scrapeOpsNode.all) {
          const scrapeOpsData = scrapeOpsNode.all() || [];
          let currentIndex = -1;
          for (let i = 0; i < scrapeOpsData.length; i++) {
            const itemHtml = scrapeOpsData[i].json.response || scrapeOpsData[i].json.body || scrapeOpsData[i].json.data || '';
            if (itemHtml === htmlContent || 
                (itemHtml && htmlContent && itemHtml.substring(0, 500) === htmlContent.substring(0, 500))) {
              currentIndex = i; break;
            }
          }
          if (currentIndex >= 0 && currentIndex < parseData.length) {
            originalData = parseData[currentIndex].json || parseData[currentIndex];
            currentMapUrl = originalData.mapUrl || '';
          } else if (inputItem.index !== undefined && inputItem.index !== null && inputItem.index < parseData.length) {
            originalData = parseData[inputItem.index].json || parseData[inputItem.index];
            currentMapUrl = originalData.mapUrl || '';
          }
        } else if (inputItem.index !== undefined && inputItem.index !== null && inputItem.index < parseData.length) {
          originalData = parseData[inputItem.index].json || parseData[inputItem.index];
          currentMapUrl = originalData.mapUrl || '';
        }
      }
      if (!originalData || Object.keys(originalData).length === 0) {
        output.push({
          json: {
            businessName: 'MATCHING_ERROR', phone: '', website: '', rating: '',
            totalReviews: '', address: '', city: '', mapUrl: extractedMapUrl || '',
            category: 'real estate agent', lgbtqFriendly: false,
            checkedAt: new Date().toISOString(),
            error: 'Could not match HTML to original business data.'
          }
        });
        continue;
      }
    }
  } catch (error) {
    output.push({
      json: {
        businessName: 'MATCHING_ERROR', phone: '', website: '', rating: '',
        totalReviews: '', address: '', city: '', mapUrl: extractedMapUrl || '',
        category: 'real estate agent', lgbtqFriendly: false,
        checkedAt: new Date().toISOString(),
        error: 'Error matching data: ' + String(error.message || 'Unknown error')
      }
    });
    continue;
  }

  if (!originalData.mapUrl && currentMapUrl) originalData.mapUrl = currentMapUrl;
  else if (!originalData.mapUrl && extractedMapUrl) originalData.mapUrl = extractedMapUrl;
  if (htmlContent.length > 2000000) htmlContent = htmlContent.substring(0, 2000000);

  function extractText(html, pattern) {
    const match = html.match(pattern);
    if (match && match[1]) return match[1].replace(/<[^>]*>/g, '').replace(/\s+/g, ' ').trim();
    return '';
  }
  function extractAllMatches(html, pattern) {
    const matches = [];
    let match;
    while ((match = pattern.exec(html)) !== null) { if (match[1]) matches.push(match[1].trim()); }
    return matches;
  }

  let businessName = originalData.businessName || '';
  let phone = originalData.phone || '';
  let website = originalData.website || '';
  let rating = '';
  let totalReviews = '';
  let address = originalData.address || '';
  let city = originalData.city || '';
  let category = originalData.category || 'real estate agent';
  let lgbtqFriendly = false;
  let review1 = '', review2 = '', review3 = '';

  if (htmlContent && htmlContent.length > 100) {

    // EXTRACT PHONE
    if (!phone || phone.length < 7) {
      const m = htmlContent.match(/data-item-id=["']phone:tel:([^"']+)["']/i);
      if (m) { phone = m[1].replace(/[^0-9+]/g, ''); if (!phone.startsWith('+')) phone = '+' + phone; }
    }
    if (!phone || phone.length < 7) {
      const telLinks = extractAllMatches(htmlContent, /href=["']tel:([^"']+)["']/gi);
      if (telLinks.length > 0) { phone = telLinks[0].replace(/[^0-9+]/g, ''); if (!phone.startsWith('+') && phone.length >= 10) phone = '+' + phone; }
    }
    if (!phone || phone.length < 7) {
      const m = htmlContent.match(/<[^>]*data-item-id=["'][^"']*phone[^"']*["'][^>]*>([\s\S]{0,500})<\/button>/i) ||
                htmlContent.match(/<[^>]*data-item-id=["'][^"']*phone[^"']*["'][^>]*>([\s\S]{0,500})<\/a>/i);
      if (m) {
        const t = m[1].match(/<[^>]*class=["'][^"']*Io6YTe[^"']*["'][^>]*>([^<]+)<\/[^>]*>/i);
        if (t) { phone = t[1].replace(/[^0-9+()-]/g, '').trim(); if (phone.length < 7 || phone.length > 15) phone = originalData.phone || ''; else if (!phone.startsWith('+') && phone.length >= 10) phone = '+' + phone; }
      }
    }

    // EXTRACT WEBSITE
    if (!website || website.length < 5) {
      const m = htmlContent.match(/<[^>]*data-item-id=["']authority["'][^>]*href=["']([^"']+)["'][^>]*>/i);
      if (m) { website = m[1]; if (website.startsWith('www.')) website = 'http://' + website; website = website.split('#')[0].trim(); if (website.includes('google.com') || website.includes('googleapis.com') || website.includes('gstatic.com')) website = originalData.website || ''; }
    }
    if (!website || website.length < 5) {
      const m = htmlContent.match(/aria-label=["']Website:[^"']*["'][^>]*href=["']([^"']+)["']/i);
      if (m) { website = m[1]; if (website.startsWith('www.')) website = 'http://' + website; website = website.split('#')[0].trim(); if (website.includes('google.com') || website.includes('googleapis.com') || website.includes('gstatic.com')) website = originalData.website || ''; }
    }

    // EXTRACT ADDRESS
    if (!address || address.length < 5) {
      const m = htmlContent.match(/<[^>]*data-item-id=["']address["'][^>]*>([\s\S]{0,500})<\/button>/i) ||
                htmlContent.match(/<[^>]*data-item-id=["']address["'][^>]*>([\s\S]{0,500})<\/div>/i);
      if (m) { const t = m[1].match(/<[^>]*class=["'][^"']*Io6YTe[^"']*["'][^>]*>([^<]+)<\/[^>]*>/i); if (t) { address = t[1].replace(/<[^>]*>/g, '').replace(/\s+/g, ' ').trim(); if (address.length < 10 || address.length > 300) address = originalData.address || ''; } }
    }
    if (!address || address.length < 5) {
      const m = htmlContent.match(/aria-label=["']Address:[^"']*["'][^>]*>([\s\S]{0,500})<\/button>/i);
      if (m) { const t = m[1].match(/<[^>]*class=["'][^"']*Io6YTe[^"']*["'][^>]*>([^<]+)<\/[^>]*>/i); if (t) { address = t[1].replace(/<[^>]*>/g, '').replace(/\s+/g, ' ').trim(); if (address.length < 10 || address.length > 300) address = originalData.address || ''; } }
    }

    // ============================================================
    // EXTRACT LGBTQ+ FRIENDLY
    // ============================================================
    const lgbtqPatterns = [
      /lgbtq[^"'<>]{0,50}friendly/i,
      /lgbt[^"'<>]{0,50}friendly/i,
      /identifies as lgbtq\+?\s*friendly/i,
      /lgbtq\+?\s*owned/i,
      /gay.friendly/i,
      /transgender.friendly/i,
      /pride[^"'<>]{0,30}friendly/i
    ];
    for (const pattern of lgbtqPatterns) {
      if (pattern.test(htmlContent)) {
        lgbtqFriendly = true;
        break;
      }
    }

    // ============================================================
    // EXTRACT RATING
    // ============================================================
    const f7niceBlock = htmlContent.match(/F7nice[^>]*>([\s\S]{0,500}?)<\/div>/i);
    if (f7niceBlock && f7niceBlock[1]) {
      const ariaHidden = f7niceBlock[1].match(/aria-hidden=(?:\\?"|\")true(?:\\?\"|\")\s*>(\d+\.?\d*)<\/span>/i);
      if (ariaHidden && ariaHidden[1]) {
        const n = parseFloat(ariaHidden[1]);
        if (n >= 1.0 && n <= 5.0) rating = ariaHidden[1];
      }
    }
    if (!rating) {
      const m = htmlContent.match(/aria-label=(?:\\?"|\")(\d+\.?\d*)\s+stars?\s*(?:\\?"|\")/i);
      if (m && m[1]) { const n = parseFloat(m[1]); if (n >= 1.0 && n <= 5.0) rating = m[1]; }
    }
    if (!rating) {
      const raw = extractText(htmlContent, /<span[^>]*class=["'][^"']*MW4etd[^"']*["'][^>]*>([^<]+)<\/span>/i).replace(/[^0-9.]/g, '');
      const n = parseFloat(raw);
      if (raw && !isNaN(n) && n >= 1.0 && n <= 5.0) rating = raw;
    }
    const ratingNum = parseFloat(rating);
    if (!rating || isNaN(ratingNum) || ratingNum < 1.0 || ratingNum > 5.0) {
      rating = originalData.rating || '';
    }

    // ============================================================
    // EXTRACT TOTAL REVIEWS
    // ============================================================
    if (f7niceBlock && f7niceBlock[1]) {
      const reviewsInBlock = f7niceBlock[1].match(/aria-label=(?:\\?"|\")([0-9,]+)\s+reviews(?:\\?"|\")/i);
      if (reviewsInBlock && reviewsInBlock[1]) totalReviews = reviewsInBlock[1].replace(/,/g, '');
      if (!totalReviews) {
        const parenInBlock = f7niceBlock[1].match(/\(([0-9,]+)\)/);
        if (parenInBlock && parenInBlock[1]) totalReviews = parenInBlock[1].replace(/,/g, '');
      }
    }
    if (!totalReviews) {
      const roleImg = htmlContent.match(/role=(?:\\?"|\"|')img(?:\\?"|\"|')[^>]*aria-label=(?:\\?"|\")([0-9,]+)\s+reviews(?:\\?"|\")[\s>]/i);
      if (roleImg && roleImg[1]) totalReviews = roleImg[1].replace(/,/g, '');
    }
    if (!totalReviews) {
      const strictMatch = htmlContent.match(/aria-label=["\\]+([0-9,]+)\s+reviews["\\]+/i);
      if (strictMatch && strictMatch[1]) totalReviews = strictMatch[1].replace(/,/g, '');
    }
    if (!totalReviews) {
      const raw = extractText(htmlContent, /<span[^>]*class=["'][^"']*UY7F9[^"']*["'][^>]*>([^<]+)<\/span>/i).replace(/[^0-9]/g, '');
      if (raw && raw.length >= 1 && raw.length <= 6) totalReviews = raw;
    }
    const totalNum = parseInt(totalReviews);
    if (!totalReviews || isNaN(totalNum) || totalNum < 1 || totalNum > 999999) {
      totalReviews = '';
    }

    // EXTRACT BUSINESS NAME
    if (!businessName || businessName.length < 3) {
      for (const p of [
        /<div[^>]*class=["'][^"']*qBF1Pd[^"']*["'][^>]*>([^<]+)<\/div>/i,
        /<h1[^>]*>([^<]+)<\/h1>/i,
        /<h2[^>]*>([^<]+)<\/h2>/i
      ]) {
        businessName = extractText(htmlContent, p);
        if (businessName && businessName.length >= 3) break;
      }
      businessName = businessName.replace(/\s+/g, ' ').trim();
      if (!businessName || businessName.length < 3) businessName = originalData.businessName || '';
    }

    // ============================================================
    // EXTRACT REVIEWS - FULL TEXT
    // ============================================================

    function cleanReviewText(text) {
      if (!text) return '';
      text = text.replace(/<[^>]*>/g, ' ');
      text = text.replace(/&amp;/g, '&').replace(/&lt;/g, '<').replace(/&gt;/g, '>').replace(/&quot;/g, '"').replace(/&#39;/g, "'").replace(/&nbsp;/g, ' ');
      text = text.replace(/\\u0026/g, '&').replace(/\\u003c/g, '<').replace(/\\u003e/g, '>').replace(/\\n/g, ' ').replace(/\\"/g, '"');
      text = text.replace(/\bMore\b/g, '').replace(/\bLess\b/g, '').replace(/\bTranslate\b/g, '');
      text = text.replace(/\bLike\b/g, '').replace(/\bShare\b/g, '').replace(/\bReport\b/g, '');
      text = text.replace(/Response from the owner[\s\S]{0,500}?(?=\s{2,}|$)/gi, '');
      text = text.replace(/Owner[''s]*\s*response[\s\S]{0,500}?(?=\s{2,}|$)/gi, '');
      text = text.replace(/^\s*[Nn][Ee][Ww]\s+/g, '');
      text = text.replace(/[★⭐☆✩✫✬✭✮✯✰]/g, '');
      text = text.replace(/\d+\s*stars?/gi, '');
      text = text.replace(/\d+\s+(days?|weeks?|months?|years?)\s+ago/gi, '');
      text = text.replace(/\b(a|an)\s+(day|week|month|year)\s+ago\b/gi, '');
      text = text.replace(/\d{1,2}\/\d{1,2}\/\d{2,4}/g, '');
      text = text.replace(/\b(January|February|March|April|May|June|July|August|September|October|November|December)\s+\d{4}\b/gi, '');
      text = text.replace(/Local\s+Guide\s*[·•]\s*\d+\s+reviews?\s*[·•]?\s*(\d+\s+photos?)?/gi, '');
      text = text.replace(/\d+\s+reviews?\s*[·•]\s*\d+\s+photos?/gi, '');
      text = text.replace(/[\uE000-\uF8FF\uFFF0-\uFFFF]/g, '');
      text = text.replace(/[\r\n\t]+/g, ' ').replace(/\s{2,}/g, ' ').trim();
      return text;
    }

    function areSimilar(a, b) {
      if (!a || !b) return false;
      const shorter = a.length < b.length ? a : b;
      const longer = a.length < b.length ? b : a;
      const checkLen = Math.min(shorter.length, 120);
      if (longer.includes(shorter.substring(0, checkLen))) return true;
      if (shorter.includes(longer.substring(0, checkLen))) return true;
      if (a.substring(0, 80) === b.substring(0, 80)) return true;
      return false;
    }

    let allCandidates = [];
    function addCandidate(text, source) {
      if (!text) return;
      const cleaned = cleanReviewText(text);
      if (!cleaned || cleaned.length < 40) return;
      if (cleaned.match(/^[\d\s\.,]+$/)) return;
      allCandidates.push({ text: cleaned, length: cleaned.length, source });
    }

    // SOURCE 1: data-expanded-text (char by char)
    const expandedAttrPattern = /data-expanded-text=/gi;
    let attrMatch;
    while ((attrMatch = expandedAttrPattern.exec(htmlContent)) !== null) {
      const startPos = attrMatch.index + 'data-expanded-text='.length;
      const quoteChar = htmlContent[startPos];
      if (quoteChar !== '"' && quoteChar !== "'") continue;
      let endPos = startPos + 1, fullText = '';
      while (endPos < htmlContent.length && endPos < startPos + 10000) {
        if (htmlContent[endPos] === quoteChar && htmlContent[endPos - 1] !== '\\') { fullText = htmlContent.substring(startPos + 1, endPos); break; }
        endPos++;
      }
      if (fullText) addCandidate(fullText, 'expanded');
    }

    // SOURCE 2: data-original-text (char by char)
    const originalTextPattern = /data-original-text=/gi;
    let origMatch;
    while ((origMatch = originalTextPattern.exec(htmlContent)) !== null) {
      const startPos = origMatch.index + 'data-original-text='.length;
      const quoteChar = htmlContent[startPos];
      if (quoteChar !== '"' && quoteChar !== "'") continue;
      let endPos = startPos + 1, fullText = '';
      while (endPos < htmlContent.length && endPos < startPos + 10000) {
        if (htmlContent[endPos] === quoteChar && htmlContent[endPos - 1] !== '\\') { fullText = htmlContent.substring(startPos + 1, endPos); break; }
        endPos++;
      }
      if (fullText) addCandidate(fullText, 'original');
    }

    // SOURCE 3: data-review-id blocks
    const reviewBlockPositions = [];
    const reviewIdFinder = /data-review-id="([^"]+)"/gi;
    let ridMatch;
    while ((ridMatch = reviewIdFinder.exec(htmlContent)) !== null) reviewBlockPositions.push({ pos: ridMatch.index, id: ridMatch[1] });
    for (let bi = 0; bi < reviewBlockPositions.length; bi++) {
      const startPos = reviewBlockPositions[bi].pos;
      const endPos = bi + 1 < reviewBlockPositions.length ? Math.min(reviewBlockPositions[bi + 1].pos, startPos + 8000) : startPos + 8000;
      const chunk = htmlContent.substring(startPos, endPos);
      const spanCandidates = [];
      const spanPat = /<span[^>]*>([\s\S]{40,3000}?)<\/span>/gi;
      let spanMatch;
      while ((spanMatch = spanPat.exec(chunk)) !== null) {
        const raw = spanMatch[1];
        if ((raw.match(/<[^>]+>/g) || []).length > 12) continue;
        const cleaned = cleanReviewText(raw);
        if (cleaned && cleaned.length >= 40) spanCandidates.push(cleaned);
      }
      spanCandidates.sort((a, b) => b.length - a.length);
      if (spanCandidates.length > 0) addCandidate(spanCandidates[0], 'review_block_' + bi);
    }

    // SOURCE 4: wiI7pd class
    const wiPat = /<span[^>]*class="[^"]*wiI7pd[^"]*"[^>]*>([\s\S]{40,8000}?)<\/span>/gi;
    let wiMatch;
    while ((wiMatch = wiPat.exec(htmlContent)) !== null) addCandidate(wiMatch[1], 'wiI7pd');

    // SOURCE 5: MyEned class
    const myPat = /<span[^>]*class="[^"]*MyEned[^"]*"[^>]*>([\s\S]{40,8000}?)<\/span>/gi;
    let myMatch;
    while ((myMatch = myPat.exec(htmlContent)) !== null) addCandidate(myMatch[1], 'MyEned');

    // SOURCE 6: rsqaWe class
    const rsqaPat = /<span[^>]*class="[^"]*rsqaWe[^"]*"[^>]*>([\s\S]{40,8000}?)<\/span>/gi;
    let rsqaMatch;
    while ((rsqaMatch = rsqaPat.exec(htmlContent)) !== null) addCandidate(rsqaMatch[1], 'rsqaWe');

    // SOURCE 7: JSON-LD
    const jsonPat = /<script[^>]*type="application\/ld\+json"[^>]*>([\s\S]*?)<\/script>/gi;
    let jsonMatch;
    while ((jsonMatch = jsonPat.exec(htmlContent)) !== null) {
      try {
        const obj = JSON.parse(jsonMatch[1]);
        const walkJson = (o) => {
          if (!o || typeof o !== 'object') return;
          if (o['@type'] === 'Review' && o.reviewBody) addCandidate(o.reviewBody, 'jsonld');
          if (Array.isArray(o)) o.forEach(walkJson);
          else Object.values(o).forEach(v => { if (typeof v === 'object') walkJson(v); });
        };
        walkJson(obj);
      } catch(e) {}
    }

    // SOURCE 8: meta reviewBody
    const metaPat = /<meta[^>]*itemprop="reviewBody"[^>]*content="([^"]{40,})"[^>]*>/gi;
    let metaMatch;
    while ((metaMatch = metaPat.exec(htmlContent)) !== null) addCandidate(metaMatch[1], 'meta');

    // DEDUPLICATE AND SELECT BEST 3
    allCandidates.sort((a, b) => b.length - a.length);
    let finalReviews = [];
    for (const candidate of allCandidates) {
      if (finalReviews.length >= 3) break;
      if (!finalReviews.some(r => areSimilar(r, candidate.text))) finalReviews.push(candidate.text);
    }

    // Fallback
    if (finalReviews.length === 0) {
      const broadCandidates = [];
      const broadPat = /<(?:span|div|p)[^>]*>([\s\S]{150,3000}?)<\/(?:span|div|p)>/gi;
      let broadMatch;
      while ((broadMatch = broadPat.exec(htmlContent)) !== null) {
        const raw = broadMatch[1];
        if ((raw.match(/<[^>]+>/g) || []).length > 8) continue;
        const cleaned = cleanReviewText(raw);
        const reviewWords = /\b(agent|realtor|property|home|house|listing|sale|purchase|buyer|seller|market|negotiation|closing|mortgage|neighborhood|recommend|professional|excellent|responsive|knowledgeable|helpful|trust|deal|offer|contract)\b/i;
        if (cleaned && cleaned.length >= 150 && reviewWords.test(cleaned)) broadCandidates.push(cleaned);
      }
      broadCandidates.sort((a, b) => b.length - a.length);
      for (const text of broadCandidates) {
        if (finalReviews.length >= 3) break;
        if (!finalReviews.some(r => areSimilar(r, text))) finalReviews.push(text);
      }
    }

    review1 = finalReviews[0] || '';
    review2 = finalReviews[1] || '';
    review3 = finalReviews[2] || '';
  }

  output.push({
    json: {
      businessName: businessName || originalData.businessName || '',
      phone: phone || originalData.phone || '',
      website: website || originalData.website || '',
      rating: rating || '',
      totalReviews: totalReviews || '',
      address: address || originalData.address || '',
      city: city || originalData.city || '',
      mapUrl: originalData.mapUrl || '',
      category: category || originalData.category || 'real estate agent',
      lgbtqFriendly: lgbtqFriendly,
      checkedAt: originalData.checkedAt || new Date().toISOString(),
      review1: review1,
      review2: review2,
      review3: review3
    }
  });
}

return output;

const item = $input.item;
const config = $('Set Google Maps Configuration').item.json;

// City validation: Check if city is valid
const cityName = config.city || config['City Name'] || '';
if (!cityName || cityName.trim().length === 0) {
  return [{
