// Helper function to extract text from HTML tag
function extractText(html, pattern) {
  const match = html.match(pattern);
  if (match && match[1]) {
    return match[1].replace(/<[^>]*>/g, '').replace(/\s+/g, ' ').trim();
  }
  return '';
}

// Helper function to extract attribute value
function extractAttribute(html, pattern) {
  const match = html.match(pattern);
  if (match && match[1]) {
    return match[1].trim();
  }
  return '';
}

// Helper function to extract all matches
function extractAllMatches(html, pattern) {
  const matches = [];
  let match;
  while ((match = pattern.exec(html)) !== null) {
    if (match[1]) {
      matches.push(match[1].trim());
    }
  }
  return matches;
}

const results = [];
const seenPlaceIds = new Set();

// NEW APPROACH: Extract by mapUrl first (most reliable identifier)
// Step 1: Find all unique mapUrls with their place IDs - use flexible pattern
const mapUrlPatterns = [
  /href=["']([^"']*maps\.google\.com[^"']*place[^"']*\/data=!4m[^"']*)["']/gi,
  /href=["']([^"']*maps\.google\.com[^"']*place[^"']*)["']/gi,
  /href=["']([^"']*google\.com\/maps\/place[^"']*)["']/gi
];

const mapUrls = [];
for (const mapUrlPattern of mapUrlPatterns) {
  let mapUrlMatch;
  while ((mapUrlMatch = mapUrlPattern.exec(htmlContent)) !== null && mapUrls.length < 100) {
    let mapUrl = mapUrlMatch[1];
    if (!mapUrl.startsWith('http')) {
      mapUrl = 'https://' + mapUrl;
    }

    // Extract place ID to ensure uniqueness
    const placeIdMatch = mapUrl.match(/1s([^:!\/]+)/) || mapUrl.match(/place\/([^\/\?]+)/);
    const placeId = placeIdMatch ? placeIdMatch[1] : mapUrl;

    if (!seenPlaceIds.has(placeId) && mapUrl.includes('place')) {
      seenPlaceIds.add(placeId);
      mapUrls.push({ mapUrl: mapUrl, placeId: placeId });
    }
  }
  if (mapUrls.length > 0) break; // Use first pattern that finds URLs
}

// If no mapUrls found, try to extract business cards from HTML structure
if (mapUrls.length === 0) {
  // Fallback: Extract business cards using HTML structure
  const cardPatterns = [
    /<div[^>]*class=["'][^"']*Nv2PK[^"']*["'][^>]*>([\s\S]{300,8000})<\/div>/gi,
    /<a[^>]*href=["'][^"']*\/maps\/place\/[^"']*["'][^>]*>([\s\S]{300,8000})<\/a>/gi,
    /<div[^>]*data-result-index[^>]*>([\s\S]{300,8000})<\/div>/gi
  ];

  const allCards = [];
  for (const pattern of cardPatterns) {
    let match;
    while ((match = pattern.exec(htmlContent)) !== null && allCards.length < 100) {
      if (match[1] && match[1].length > 200) {
        allCards.push(match[1]);
      }
    }
    if (allCards.length > 0) break;
  }

  // Process cards and extract mapUrls from them
  for (const cardHtml of allCards) {
    const cardMapUrlMatch = cardHtml.match(/href=["']([^"']*maps\.google\.com[^"']*place[^"']*)["']/i) ||
                              cardHtml.match(/href=["']([^"']*google\.com\/maps\/place[^"']*)["']/i);
    if (cardMapUrlMatch && cardMapUrlMatch[1]) {
      let mapUrl = cardMapUrlMatch[1];
      if (!mapUrl.startsWith('http')) {
        mapUrl = 'https://' + mapUrl;
      }
      const placeIdMatch = mapUrl.match(/1s([^:!\/]+)/) || mapUrl.match(/place\/([^\/\?]+)/);
      const placeId = placeIdMatch ? placeIdMatch[1] : mapUrl;
      if (!seenPlaceIds.has(placeId)) {
        seenPlaceIds.add(placeId);
        mapUrls.push({ mapUrl: mapUrl, placeId: placeId, cardHtml: cardHtml });
      }
    } else {
      // Even without mapUrl, try to extract business info from card
      const businessName = extractText(cardHtml, /<div[^>]*class=["'][^"']*qBF1Pd[^"']*["'][^>]*>([^<]+)<\/div>/i) ||
                          extractText(cardHtml, /<h3[^>]*>([^<]+)<\/h3>/i) ||
                          extractAttribute(cardHtml, /aria-label=["']([^"']+)["']/i) ||
                          '';
      if (businessName && businessName.trim().length > 2) {
        const cardId = 'card_' + allCards.indexOf(cardHtml);
        if (!seenPlaceIds.has(cardId)) {
          seenPlaceIds.add(cardId);
          mapUrls.push({ mapUrl: '', placeId: cardId, cardHtml: cardHtml });
        }
      }
    }
  }
}

// Step 2: For each mapUrl, find its card and extract all data
for (const { mapUrl: currentMapUrl, placeId, cardHtml: preExtractedCard } of mapUrls) {
  // Use pre-extracted card if available, otherwise find the card
  let cardHtml = preExtractedCard || '';
  let mapUrlIndex = -1;

  if (!cardHtml) {
    // Find the card that contains this mapUrl
    mapUrlIndex = htmlContent.indexOf(currentMapUrl);
    if (mapUrlIndex === -1) continue;

    // Extract a card context around this mapUrl (3000 chars before and after)
    const cardStart = Math.max(0, mapUrlIndex - 3000);
    const cardEnd = Math.min(htmlContent.length, mapUrlIndex + currentMapUrl.length + 3000);
    cardHtml = htmlContent.substring(cardStart, cardEnd);
  } else {
    mapUrlIndex = cardHtml.indexOf(currentMapUrl);
    if (mapUrlIndex === -1) mapUrlIndex = 0; // Use start if not found
  }

  // Try to find the actual card boundaries (only if not pre-extracted)
  if (!preExtractedCard && mapUrlIndex >= 0) {
    const cardStartPattern = /<div[^>]*(?:class=["'][^"']*(?:Nv2PK|qBF1Pd|result)[^"']*["']|data-result-index)[^>]*>/i;

    // Find the start of the card
    const cardStart = Math.max(0, mapUrlIndex - 3000);
    let actualStart = cardStart;
    for (let i = mapUrlIndex; i >= Math.max(0, mapUrlIndex - 3000); i -= 100) {
      const checkHtml = htmlContent.substring(Math.max(0, i - 500), mapUrlIndex);
      const startMatch = checkHtml.match(cardStartPattern);
      if (startMatch) {
        actualStart = Math.max(0, i - 500) + checkHtml.lastIndexOf(startMatch[0]);
        break;
      }
    }

    // Find the end of the card
    const cardEnd = Math.min(htmlContent.length, mapUrlIndex + currentMapUrl.length + 3000);
    let actualEnd = cardEnd;
    let divCount = 0;
    let foundStart = false;
    for (let i = actualStart; i < Math.min(htmlContent.length, actualStart + 5000); i++) {
      if (htmlContent.substring(i, i + 4) === '<div') {
        divCount++;
        foundStart = true;
      } else if (htmlContent.substring(i, i + 6) === '</div>') {
        divCount--;
        if (foundStart && divCount === 0) {
          actualEnd = i + 6;
          break;
        }
      }
    }

    cardHtml = htmlContent.substring(actualStart, actualEnd);
    mapUrlIndex = cardHtml.indexOf(currentMapUrl);
    if (mapUrlIndex === -1) mapUrlIndex = 0;
  }

  if (cardHtml.length < 200) continue;

  // STEP 1: Extract business name and address from mapUrl (most reliable)
  let businessName = '';
  let address = '';

  // Try to extract mapUrl from card if not provided
  if (!currentMapUrl || currentMapUrl.length === 0) {
    const cardMapUrlMatch = cardHtml.match(/href=["']([^"']*maps\.google\.com[^"']*place[^"']*)["']/i) ||
                              cardHtml.match(/href=["']([^"']*google\.com\/maps\/place[^"']*)["']/i);
    if (cardMapUrlMatch && cardMapUrlMatch[1]) {
      currentMapUrl = cardMapUrlMatch[1];
      if (!currentMapUrl.startsWith('http')) {
        currentMapUrl = 'https://' + currentMapUrl;
      }
      mapUrlIndex = cardHtml.indexOf(currentMapUrl);
      if (mapUrlIndex === -1) mapUrlIndex = 0;
    }
  }

  const placeMatch = currentMapUrl ? currentMapUrl.match(/\/place\/([^\/]+)/) : null;
  if (placeMatch && placeMatch[1]) {
    let placePath = decodeURIComponent(placeMatch[1]);
    placePath = placePath.replace(/\+/g, ' ').trim();

    // Split by ' - ' or ' | ' - business name is usually first, address is after
    const parts = placePath.split(/\s*[-|]\s*/);
    if (parts.length >= 2) {
      businessName = parts[0].trim();
      // Address is everything after the first part
      address = parts.slice(1).join(', ').trim();
    } else if (parts.length === 1) {
      businessName = parts[0].trim();
    }

    // Clean business name - remove pipe separators and trailing location info
    businessName = businessName
      .replace(/\s*\|.*$/i, '')
      .trim();

    // Clean address - remove business name words if they appear
    if (address && businessName) {
      const nameWords = businessName.split(/\s+/).filter(w => w.length > 4);
      let cleanedAddress = address;
      for (const word of nameWords) {
        const wordRegex = new RegExp(word.replace(/[.*+?^${}()|[\]\\]/g, '\\$&'), 'gi');
        cleanedAddress = cleanedAddress.replace(wordRegex, '');
      }
      address = cleanedAddress.replace(/^[-|,\s]+|[-|,\s]+$/g, '').trim();

      // If address is too short or looks like business name, clear it
      if (address.length < 5 || address.toLowerCase().includes(businessName.toLowerCase().substring(0, 15))) {
        address = '';
      }
    }
  }

  // If no business name from mapUrl, try HTML extraction with multiple patterns
  if (!businessName || businessName.length < 3) {
    const namePatterns = [
      /<div[^>]*class=["'][^"']*qBF1Pd[^"']*["'][^>]*>([^<]+)<\/div>/i,
      /<h3[^>]*>([^<]+)<\/h3>/i,
      /<a[^>]*href=["'][^"']*\/maps\/place[^"']*["'][^>]*>([^<]+)<\/a>/i,
      /<span[^>]*class=["'][^"']*qBF1Pd[^"']*["'][^>]*>([^<]+)<\/span>/i,
      /<div[^>]*class=["'][^"']*fontHeadlineSmall[^"']*["'][^>]*>([^<]+)<\/div>/i,
      /<div[^>]*role=["']heading["'][^>]*>([^<]+)<\/div>/i,
      /aria-label=["']([^"']+)["']/i
    ];

    for (const pattern of namePatterns) {
      businessName = extractText(cardHtml, pattern) || extractAttribute(cardHtml, pattern) || '';
      if (businessName && businessName.length >= 3) break;
    }

    businessName = businessName.replace(/\s+/g, ' ').trim();
  }

  // Filter invalid names
  if (!businessName || businessName.length < 3 || businessName.length > 150 ||
      /^(directions|save|share|more|view|see|click|here|search|map)$/i.test(businessName)) {
    continue;
  }

  // STEP 2: Extract rating and reviews from card
  let rating = '';
  rating = extractText(cardHtml, /<span[^>]*class=["'][^"']*MW4etd[^"']*["'][^>]*>([^<]+)<\/span>/i) ||
           extractText(cardHtml, /(\d+\.?\d*)\s*(?:star)/i) ||
           '';
  rating = rating.replace(/[^0-9.]/g, '').trim();

  let totalReviews = '';
  totalReviews = extractText(cardHtml, /<span[^>]*class=["'][^"']*UY7F9[^"']*["'][^>]*>([^<]+)<\/span>/i) ||
                 extractText(cardHtml, /(\d+(?:,\d+)?)\s*(?:review)/i) ||
                 extractText(cardHtml, /\((\d+(?:,\d+)?)\)/i) ||
                 '';
  totalReviews = totalReviews.replace(/[^0-9,]/g, '').trim();

  // STEP 3: Extract address from Google Maps HTML
  // Note: mapUrl path usually only contains business name, not full address
  // So we must extract address from HTML elements
  if (!address || address.length < 5) {
    // Method 1: Extract from data-item-id="address" (MOST RELIABLE)
    const addressSectionMatch = cardHtml.match(/<[^>]*data-item-id=["']address["'][^>]*>([\s\S]{0,500})<\/button>/i) ||
                                cardHtml.match(/<[^>]*data-item-id=["']address["'][^>]*>([\s\S]{0,500})<\/div>/i);
    if (addressSectionMatch && addressSectionMatch[1]) {
      const addressTextMatch = addressSectionMatch[1].match(/<[^>]*class=["'][^"']*Io6YTe[^"']*["'][^>]*>([^<]+)<\/[^>]*>/i);
      if (addressTextMatch && addressTextMatch[1]) {
        address = addressTextMatch[1].replace(/<[^>]*>/g, '').replace(/\s+/g, ' ').trim();
        if (address.length > 10 && address.length < 300) {
          // Found address from data-item-id
        } else {
          address = '';
        }
      }
    }

    // Method 2: Extract from aria-label="Address:"
    if (!address || address.length < 5) {
      const addressAriaMatch = cardHtml.match(/aria-label=["']Address:[^"']*["'][^>]*>([\s\S]{0,500})<\/button>/i);
      if (addressAriaMatch && addressAriaMatch[1]) {
        const addressTextMatch = addressAriaMatch[1].match(/<[^>]*class=["'][^"']*Io6YTe[^"']*["'][^>]*>([^<]+)<\/[^>]*>/i);
        if (addressTextMatch && addressTextMatch[1]) {
          address = addressTextMatch[1].replace(/<[^>]*>/g, '').replace(/\s+/g, ' ').trim();
          if (address.length > 10 && address.length < 300) {
            // Found address from aria-label
          } else {
            address = '';
          }
        }
      }
    }

    // Method 3: Fallback - extract from Io6YTe elements and filter
    if (!address || address.length < 5) {
      const addressPatterns = [
        /<div[^>]*class=["'][^"']*Io6YTe[^"']*["'][^>]*>([^<]+)<\/div>/gi,
        /<span[^>]*class=["'][^"']*Io6YTe[^"']*["'][^>]*>([^<]+)<\/span>/gi
      ];

      const allAddressCandidates = [];
      for (const pattern of addressPatterns) {
        const matches = extractAllMatches(cardHtml, pattern);
        for (const match of matches) {
          const cleanMatch = match.replace(/<[^>]*>/g, '').replace(/\s+/g, ' ').trim();
          if (cleanMatch.length > 10 && cleanMatch.length < 300) {
            allAddressCandidates.push(cleanMatch);
          }
        }
      }

      // Filter and select the best address candidate
      for (const candidate of allAddressCandidates) {
        // Skip if it's a phone number
        if (candidate.match(/^\+?[\d\s\-\(\)]{10,20}$/) && 
            (candidate.match(/\+/) || candidate.match(/\(?\d{3}\)?[\s.-]?\d{3}[\s.-]?\d{4}/))) {
          continue;
        }
        // Skip common non-address text
        if (candidate.match(/^(Open|Closed|Call|Website|Directions|Save|Share|Hours|Monday|Tuesday|Wednesday|Thursday|Friday|Saturday|Sunday|nexhealth|souldentalnyc|P2Q2|Your Maps activity|LGBTQ|women-owned)$/i)) {
          continue;
        }
        // Skip if it's just the business name
        if (businessName && candidate.toLowerCase().includes(businessName.toLowerCase().substring(0, 20))) {
          continue;
        }
        // Prefer candidates that look like addresses (contain comma, numbers, or street indicators)
        if (candidate.includes(',') || candidate.match(/\d/) || 
            candidate.match(/\b(street|st|avenue|ave|road|rd|boulevard|blvd|drive|dr|lane|ln|way|circle|ct|court|plaza|pl|suite|ste|unit|apt|apartment|floor|fl|w|e|n|s|north|south|east|west)\b/i)) {
          address = candidate;
          break;
        }
      }
    }
  }

  // STEP 4: Extract phone from Google Maps HTML
  let phone = '';

  // Method 1: Extract from data-item-id="phone:tel:" attribute (MOST RELIABLE)
  const phoneDataIdMatch = cardHtml.match(/data-item-id=["']phone:tel:([^"']+)["']/i);
  if (phoneDataIdMatch && phoneDataIdMatch[1]) {
    phone = phoneDataIdMatch[1].replace(/[^0-9+]/g, '');
    if (!phone.startsWith('+')) {
      phone = '+' + phone;
    }
  }

  // Method 2: Extract from tel: href links
  if (!phone || phone.length < 7) {
    const telLinks = extractAllMatches(cardHtml, /href=["']tel:([^"']+)["']/gi);
    if (telLinks.length > 0) {
      let rawPhone = telLinks[0];
      phone = rawPhone.replace(/[^0-9+]/g, '');
      if (!phone.startsWith('+') && phone.length >= 10) {
        phone = '+' + phone;
      }
    }
  }

  // Method 3: Extract from Io6YTe element with phone pattern (near data-item-id="phone")
  if (!phone || phone.length < 7) {
    // Find the phone section by looking for data-item-id containing "phone"
    const phoneSectionMatch = cardHtml.match(/<[^>]*data-item-id=["'][^"']*phone[^"']*["'][^>]*>([\s\S]{0,500})<\/button>/i) ||
                              cardHtml.match(/<[^>]*data-item-id=["'][^"']*phone[^"']*["'][^>]*>([\s\S]{0,500})<\/a>/i);
    if (phoneSectionMatch && phoneSectionMatch[1]) {
      const phoneTextMatch = phoneSectionMatch[1].match(/<[^>]*class=["'][^"']*Io6YTe[^"']*["'][^>]*>([^<]+)<\/[^>]*>/i);
      if (phoneTextMatch && phoneTextMatch[1]) {
        phone = phoneTextMatch[1].replace(/[^0-9+()-]/g, '').trim();
        if (phone.length >= 7 && phone.length <= 15) {
          // Format phone - ensure + prefix if it looks international
          if (!phone.startsWith('+') && phone.length >= 10) {
            phone = '+' + phone;
          }
        } else {
          phone = '';
        }
      }
    }
  }

  // Method 4: Extract from visible text patterns in Io6YTe elements (fallback)
  if (!phone || phone.length < 7) {
    const phoneElements = extractAllMatches(cardHtml, /<[^>]*class=["'][^"']*Io6YTe[^"']*["'][^>]*>([^<]+)<\/[^>]*>/gi);
    for (const element of phoneElements) {
      const cleanElement = element.replace(/<[^>]*>/g, '').replace(/\s+/g, ' ').trim();
      // Check if this looks like a phone number
      if (cleanElement.match(/^\+?[\d\s\-\(\)]{10,20}$/) && 
          (cleanElement.match(/\+/) || cleanElement.match(/\(?\d{3}\)?[\s.-]?\d{3}[\s.-]?\d{4}/))) {
        phone = cleanElement.replace(/[^0-9+()-]/g, '').trim();
        if (phone.length >= 7 && phone.length <= 15) {
          if (!phone.startsWith('+') && phone.length >= 10) {
            phone = '+' + phone;
          }
          break;
        }
      }
    }
  }

  // STEP 6: Extract website from Google Maps HTML
  let website = '';

  // Method 1: Extract from data-item-id="authority" (MOST RELIABLE - Google Maps uses this)
  const websiteSectionMatch = cardHtml.match(/<[^>]*data-item-id=["']authority["'][^>]*href=["']([^"']+)["'][^>]*>/i);
  if (websiteSectionMatch && websiteSectionMatch[1]) {
    website = websiteSectionMatch[1];
    if (website.startsWith('www.')) {
      website = 'http://' + website;
    }
    // Keep query parameters (like utm_campaign) but clean up
    website = website.split('#')[0].trim();
  }

  // Method 2: Extract from aria-label="Website:" attribute
  if (!website) {
    const websiteAriaMatch = cardHtml.match(/aria-label=["']Website:[^"']*["'][^>]*href=["']([^"']+)["']/i);
    if (websiteAriaMatch && websiteAriaMatch[1]) {
      website = websiteAriaMatch[1];
      if (website.startsWith('www.')) {
        website = 'http://' + website;
      }
      website = website.split('#')[0].trim();
    }
  }

  // Method 3: Extract from href links near data-item-id="authority"
  if (!website) {
    const authoritySectionMatch = cardHtml.match(/<[^>]*data-item-id=["']authority["'][^>]*>([\s\S]{0,500})<\/a>/i);
    if (authoritySectionMatch && authoritySectionMatch[1]) {
      const hrefMatch = authoritySectionMatch[1].match(/href=["']([^"']+)["']/i);
      if (hrefMatch && hrefMatch[1]) {
        website = hrefMatch[1];
        if (website.startsWith('www.')) {
          website = 'http://' + website;
        }
        if (!website.includes('google.com') && !website.includes('maps.google.com') &&
            !website.includes('googleapis.com') && !website.includes('gstatic.com') &&
            (website.startsWith('http://') || website.startsWith('https://'))) {
          website = website.split('#')[0].trim();
        } else {
          website = '';
        }
      }
    }
  }

  // Method 4: Fallback - find website links in the card (excluding Google domains)
  if (!website) {
    const cardLinks = extractAllMatches(cardHtml, /href=["']([^"']+)["']/gi);
    for (const link of cardLinks) {
      if (link && !link.includes('google.com/maps') && !link.includes('maps.google.com') && 
          !link.includes('googleapis.com') && !link.includes('gstatic.com') &&
          !link.includes('nexhealth.com') && !link.includes('zocdoc.com') &&
          !link.startsWith('tel:') && !link.startsWith('mailto:') && !link.startsWith('#') &&
          (link.startsWith('http://') || link.startsWith('https://') || link.startsWith('www.'))) {
        website = link;
        if (website.startsWith('www.')) {
          website = 'http://' + website;
        }
        website = website.split('#')[0].trim();
        break;
      }
    }
  }

  website = website.trim();

  // Only add if we have at least a business name
  if (businessName && businessName.length > 2) {
    results.push({
      json: {
        businessName: businessName,
        phone: phone || '',
        website: website || '',
        rating: rating || '',
        totalReviews: totalReviews || '',
        address: address || '',
        city: config.city || '',
        mapUrl: currentMapUrl || '',
        category: config.keyword || 'real estate agent',
        checkedAt: new Date().toISOString()
      }
    });
  }
}

// City validation: Return error if no businesses found
