return results;

// Helper function to normalize phone numbers (remove all non-digit characters)
function normalizePhone(phone) {
  if (!phone) return '';
  let normalized = String(phone).replace(/[^0-9+]/g, '');
  if (normalized.startsWith('+')) {
    normalized = '+' + normalized.substring(1).replace(/[^0-9]/g, '');
  } else {
    normalized = normalized.replace(/[^0-9]/g, '');
  }
  return normalized;
}

// Helper function to normalize business names (trim, lowercase, remove extra spaces)
function normalizeBusinessName(name) {
  if (!name) return '';
  return String(name).trim().toLowerCase().replace(/\s+/g, ' ');
}

