      phone: '',
      website: '',
      rating: '',
      totalReviews: '',
      address: '',
      city: '',
      mapUrl: '',
      category: 'real estate agent',
      lgbtqFriendly: false,
      status: 'old',
      checkedAt: new Date().toISOString()
    }
  }];
}

// Get previous entries from Google Sheets
let previousItems = [];
try {
  const readNode = $('Read Previous Entries from Sheet');
  if (readNode && readNode.all) {
    const prevData = readNode.all() || [];
    previousItems = prevData.map(item => {
      const json = item.json || item;
      return {
        businessName: String(json.businessName || json.BusinessName || json['Business Name'] || ''),
        phone: String(json.phone || json.Phone || json['Phone'] || ''),
        website: String(json.website || json.Website || json['Website'] || ''),
        rating: String(json.rating || json.Rating || json['Rating'] || ''),
        totalReviews: String(json.totalReviews || json.TotalReviews || json['Total Reviews'] || ''),
        address: String(json.address || json.Address || json['Address'] || ''),
        city: String(json.city || json.City || json['City'] || ''),
        mapUrl: String(json.mapUrl || json.MapUrl || json['Map URL'] || ''),
        category: String(json.category || json.Category || json['Category'] || ''),
        lgbtqFriendly: json.lgbtqFriendly || json.LgbtqFriendly || json['Lgbtq Friendly'] || false,
        status: String(json.status || json.Status || json['Status'] || '')
      };
    }).filter(prev => prev.businessName && String(prev.businessName).length > 0);
  }
} catch (error) {
  previousItems = [];
}

// Create a set of normalized previous business+phone combinations
const prevKeys = new Set();
previousItems.forEach(prev => {
  const normalizedName = normalizeBusinessName(prev.businessName);
  const normalizedPhone = normalizePhone(prev.phone);
  if (normalizedName && normalizedName.length > 0) {
    const key = `${normalizedName}||${normalizedPhone}`;
    prevKeys.add(key);
    if (normalizedPhone && normalizedPhone.length > 0) {
      prevKeys.add(normalizedName);
    }
  }
});

// Process current items and mark as new or old
const results = [];
const seen = new Set();

currentItems.forEach(item => {
  const originalBusinessName = String(item.businessName || '').trim();
  const originalPhone = String(item.phone || '').trim();

  const normalizedName = normalizeBusinessName(originalBusinessName);
  const normalizedPhone = normalizePhone(originalPhone);

  const currentKey = `${normalizedName}||${normalizedPhone}`;

  if (seen.has(currentKey)) {
    return;
  }
  seen.add(currentKey);

  let isExisting = false;
  if (normalizedPhone && normalizedPhone.length > 0) {
    const exactKey = `${normalizedName}||${normalizedPhone}`;
    isExisting = prevKeys.has(exactKey);
  }

  if (!isExisting && normalizedName && normalizedName.length > 0) {
    isExisting = prevKeys.has(normalizedName);
  }

  if (!isExisting) {
    for (const prev of previousItems) {
      const prevNormalizedName = normalizeBusinessName(prev.businessName);
      const prevNormalizedPhone = normalizePhone(prev.phone);

      if (normalizedName === prevNormalizedName) {
        if (normalizedPhone && normalizedPhone.length > 0 && prevNormalizedPhone && prevNormalizedPhone.length > 0) {
          if (normalizedPhone === prevNormalizedPhone) {
            isExisting = true;
            break;
          }
        } else {
          isExisting = true;
          break;
        }
      }
    }
  }

  const status = isExisting ? 'old' : 'new';

  results.push({
    json: {
      businessName: originalBusinessName,
      phone: originalPhone,
      website: String(item.website || ''),
      rating: String(item.rating || ''),
      totalReviews: String(item.totalReviews || ''),
      address: String(item.address || ''),
      city: String(item.city || ''),
      mapUrl: String(item.mapUrl || ''),
      category: String(item.category || 'real estate agent'),
      lgbtqFriendly: item.lgbtqFriendly || false,
      status: status,
      checkedAt: String(item.checkedAt || new Date().toISOString()),
      review1: String(item.review1 || ''),
      review2: String(item.review2 || ''),
      review3: String(item.review3 || '')
    }
  });
});

return results.length > 0 ? results : [{
  json: {
    businessName: 'No data',
    phone: '',
    website: '',
    rating: '',
    totalReviews: '',
    address: '',
    city: '',
    mapUrl: '',
    category: 'real estate agent',
    lgbtqFriendly: false,
    status: 'old',
    checkedAt: new Date().toISOString()
  }
}];
